insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('5eafd7e2-f699-4b44-9084-397ee227712f', 'builder', 'parent', 'ai_safety', 'ai_safety', 'What is a robot brain?', 'Understanding that AI learns from examples, and gets things wrong.', 'AI will be the water this generation swims in. This strand teaches what it is, what it is not, and how to use it to grow rather than shrink.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Understanding that AI learns from examples, and gets things wrong.', 'My child is 8 to 10. Help me with the lesson topic: What is a robot brain?.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('dada5050-5fbb-4138-94dc-717f9d3cbe8e', 'builder', 'parent', 'bullying', 'bullying', 'Mean messages', 'What to do, what not to do, and who to tell when messages turn unkind.', 'Every child will see unkindness online. This strand makes sure they know what to do, whether it lands on them or someone else.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'What to do, what not to do, and who to tell when messages turn unkind.', 'My child is 8 to 10. Help me with the lesson topic: Mean messages.', 500, 'stub') on conflict do nothing;
