insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('d0038b85-e692-4093-bd18-7abf5b040c18', 'foundation', 'parent', 'ownership', 'ownership', 'Someone made that', 'Understanding that pictures, songs and games belong to the people who made them.', 'Everything online was made by someone. This strand teaches respect for other peoples work and pride in your own.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Understanding that pictures, songs and games belong to the people who made them.', 'My child is 4 to 7. Help me with the lesson topic: Someone made that.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('d6acfb58-0605-49b6-95ab-e087e66729e3', 'foundation', 'parent', 'privacy', 'privacy', 'My privacy shield', 'Knowing what we never tell a screen: name, school, address, passwords.', 'Personal information is valuable and children give it away without knowing. This strand builds the privacy shield early and keeps it growing.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Knowing what we never tell a screen: name, school, address, passwords.', 'My child is 4 to 7. Help me with the lesson topic: My privacy shield.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('e3c79270-ca52-4ae7-8151-873d85768ceb', 'foundation', 'parent', 'relationships', 'relationships', 'Kind words on screens', 'Speaking to people through a screen the way you would face to face.', 'Connection is the strongest protective factor in all the research. This strand teaches warmth, boundaries and judgement with people through screens.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Speaking to people through a screen the way you would face to face.', 'My child is 4 to 7. Help me with the lesson topic: Kind words on screens.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('5fb2a193-5f80-4dca-8ba3-2ceb14462579', 'foundation', 'parent', 'reputation', 'reputation', 'The internet remembers', 'Understanding that what goes on a screen can stay there.', 'What goes online stays reachable. This strand builds the habit of thinking in years, not minutes.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Understanding that what goes on a screen can stay there.', 'My child is 4 to 7. Help me with the lesson topic: The internet remembers.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('4bd125d1-4790-4153-9fd1-7cf3865af0f7', 'foundation', 'parent', 'wellbeing', 'wellbeing', 'Screens, sleep and growing bodies', 'Why screens live outside the bedroom from the very start.', 'Sleep, mood and movement are where screens bite first. This strand builds routines that protect all three without a daily fight.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Why screens live outside the bedroom from the very start.', 'My child is 4 to 7. Help me with the lesson topic: Screens, sleep and growing bodies.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('21d3a2b3-a59e-44ae-a1af-c5f612d57423', 'foundation', 'teacher', 'ai_safety', 'ai_safety', 'Some voices are not people', 'Knowing that assistants and characters are tools, not friends.', 'AI will be the water this generation swims in. This strand teaches what it is, what it is not, and how to use it to grow rather than shrink.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Knowing that assistants and characters are tools, not friends.', 'My child is 4 to 7. Help me with the lesson topic: Some voices are not people.', 500, 'stub') on conflict do nothing;
